import React, { useEffect, useState, useCallback } from 'react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend,
} from 'recharts';
import { fetchDailyBreakdown } from '../services/api';

const RANGE_OPTIONS = [
  { label: '7 d', value: 7 },
  { label: '14 d', value: 14 },
  { label: '30 d', value: 30 },
  { label: '60 d', value: 60 },
];

const METRIC_DEFS = [
  { key: 'views', label: 'Views', color: '#f43f5e', fill: 'rgba(244,63,94,0.08)' },
  { key: 'likes', label: 'Likes', color: '#6366f1', fill: 'rgba(99,102,241,0.08)' },
  { key: 'shares', label: 'Shares', color: '#06b6d4', fill: 'rgba(6,182,212,0.08)' },
  { key: 'saves', label: 'Saves', color: '#8b5cf6', fill: 'rgba(139,92,246,0.08)' },
  { key: 'engagement', label: 'Engagement', color: '#10b981', fill: 'rgba(16,185,129,0.08)' },
];

function fmt(v) {
  if (v >= 1e6) return `${(v / 1e6).toFixed(1)}M`;
  if (v >= 1e3) return `${(v / 1e3).toFixed(1)}k`;
  return String(v);
}

function computeSummary(data) {
  if (data.length < 2) return null;
  const half = Math.floor(data.length / 2);
  const recent = data.slice(half);
  const earlier = data.slice(0, half);

  const sum = (arr, k) => arr.reduce((s, r) => s + (r[k] || 0), 0);

  const metrics = ['views', 'likes', 'shares', 'saves'];
  const result = {};
  for (const m of metrics) {
    const recentSum = sum(recent, m);
    const earlierSum = sum(earlier, m);
    const pct = earlierSum > 0 ? (((recentSum - earlierSum) / earlierSum) * 100).toFixed(1) : null;
    result[m] = { recent: recentSum, earlier: earlierSum, pct };
  }
  return result;
}

export default function DataMetricsTab() {
  const [data, setData] = useState([]);
  const [days, setDays] = useState(30);
  const [visible, setVisible] = useState({ views: true, likes: true, shares: true, saves: true, engagement: false });
  const [loading, setLoading] = useState(true);

  const load = useCallback(() => {
    setLoading(true);
    fetchDailyBreakdown(days)
      .then((res) => setData(res.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [days]);

  useEffect(() => {
    load();
  }, [load]);

  const toggleMetric = (key) =>
    setVisible((prev) => ({ ...prev, [key]: !prev[key] }));

  const summary = computeSummary(data);

  if (loading) {
    return (
      <div className="card card-chart data-metrics-card">
        <div className="influencer-table-skeleton">
          {[1, 2, 3].map((i) => <div key={i} className="influencer-skel-row" />)}
        </div>
      </div>
    );
  }

  if (data.length === 0) {
    return (
      <div className="card card-chart data-metrics-card">
        <div className="empty-state empty-state--soft">
          <span className="empty-state-icon" aria-hidden>📈</span>
          <p>No daily data yet — run a scrape to see growth comparison.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="data-metrics-wrapper">
      {summary && (
        <div className="data-metrics-summary-row">
          {['views', 'likes', 'shares', 'saves'].map((m) => {
            const s = summary[m];
            if (!s) return null;
            const up = s.pct !== null && Number(s.pct) >= 0;
            return (
              <div key={m} className="data-metrics-summary-card">
                <div className="data-metrics-summary-label">{m}</div>
                <div className="data-metrics-summary-value">{fmt(s.recent)}</div>
                {s.pct !== null && (
                  <div className={`data-metrics-summary-delta ${up ? 'delta-up' : 'delta-down'}`}>
                    {up ? '↑' : '↓'} {Math.abs(Number(s.pct))}%
                    <span className="data-metrics-summary-vs"> vs prior half</span>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      <div className="card card-chart data-metrics-card">
        <div className="card-header">
          <div>
            <h2>Growth comparison</h2>
            <p className="muted-caption">
              Daily aggregated metrics — toggle series below to compare
            </p>
          </div>
          <div className="data-metrics-range">
            {RANGE_OPTIONS.map((opt) => (
              <button
                key={opt.value}
                type="button"
                className={`data-metrics-range-btn ${days === opt.value ? 'active' : ''}`}
                onClick={() => setDays(opt.value)}
              >
                {opt.label}
              </button>
            ))}
          </div>
        </div>

        <div className="data-metrics-toggles">
          {METRIC_DEFS.map((m) => (
            <label
              key={m.key}
              className={`data-metrics-toggle ${visible[m.key] ? 'active' : ''}`}
              style={{ '--toggle-color': m.color }}
            >
              <input
                type="checkbox"
                checked={!!visible[m.key]}
                onChange={() => toggleMetric(m.key)}
              />
              <span
                className="data-metrics-toggle-dot"
                style={{ background: m.color }}
              />
              {m.label}
            </label>
          ))}
        </div>

        <ResponsiveContainer width="100%" height={380}>
          <AreaChart data={data} margin={{ left: 4, right: 4, top: 8, bottom: 0 }}>
            <defs>
              {METRIC_DEFS.map((m) => (
                <linearGradient key={m.key} id={`grad-${m.key}`} x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor={m.color} stopOpacity={0.2} />
                  <stop offset="95%" stopColor={m.color} stopOpacity={0} />
                </linearGradient>
              ))}
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#e8ecf1" />
            <XAxis
              dataKey="date"
              tick={{ fontSize: 11 }}
              tickFormatter={(d) => {
                const parts = d.split('-');
                return `${parts[1]}/${parts[2]}`;
              }}
            />
            <YAxis
              tick={{ fontSize: 11 }}
              tickFormatter={fmt}
            />
            <Tooltip
              formatter={(value, name) => [
                typeof value === 'number' ? value.toLocaleString() : value,
                METRIC_DEFS.find((m) => m.key === name)?.label || name,
              ]}
              labelFormatter={(d) => {
                const date = new Date(d);
                return date.toLocaleDateString(undefined, {
                  weekday: 'short',
                  month: 'short',
                  day: 'numeric',
                });
              }}
              contentStyle={{
                borderRadius: 12,
                border: '1px solid #e2e8f0',
                boxShadow: '0 8px 24px rgba(15,23,42,.12)',
                fontSize: '0.82rem',
              }}
            />
            <Legend
              formatter={(value) =>
                METRIC_DEFS.find((m) => m.key === value)?.label || value
              }
            />
            {METRIC_DEFS.map(
              (m) =>
                visible[m.key] && (
                  <Area
                    key={m.key}
                    type="monotone"
                    dataKey={m.key}
                    stroke={m.color}
                    strokeWidth={2.5}
                    fill={`url(#grad-${m.key})`}
                    dot={false}
                    activeDot={{ r: 4 }}
                  />
                )
            )}
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}
